import java.util.ArrayList;
import java.util.List;

public class BasicArrayList {
    public static void main(String[] args) {
        // Create an ArrayList of Strings
        List<String> fruits = new ArrayList<>();

        // Add elements
        fruits.add("Apple");
        fruits.add("Banana");
        fruits.add("Cherry");
        fruits.add("Date");

        // Print the list
        System.out.println("Fruits: " + fruits);

        // Access by index
        System.out.println("First fruit: " + fruits.get(0));
        System.out.println("Third fruit: " + fruits.get(2));

        // Size of the list
        System.out.println("Number of fruits: " + fruits.size());

        // Remove an element by value
        fruits.remove("Banana");
        System.out.println("After removing Banana: " + fruits);

        // Remove by index
        fruits.remove(0);
        System.out.println("After removing index 0: " + fruits);

        // Check if element exists
        System.out.println("Contains Cherry: " + fruits.contains("Cherry"));

        // Update an element
        fruits.set(0, "Mango");
        System.out.println("After update: " + fruits);
    }
}

import java.util.ArrayList;
import java.util.Collections;
import java.util.Iterator;
import java.util.List;

public class IntermediateArrayList {
    public static void main(String[] args) {
        List<Integer> numbers = new ArrayList<>();
        numbers.add(45);
        numbers.add(12);
        numbers.add(78);
        numbers.add(23);
        numbers.add(56);
        numbers.add(12); // duplicate

        System.out.println("Original: " + numbers);

        // Sort in ascending order
        Collections.sort(numbers);
        System.out.println("Sorted ascending: " + numbers);

        // Sort in descending order
        Collections.sort(numbers, Collections.reverseOrder());
        System.out.println("Sorted descending: " + numbers);

        // Binary search (list must be sorted ascending first)
        Collections.sort(numbers);
        int index = Collections.binarySearch(numbers, 45);
        System.out.println("Index of 45: " + index);

        // Iterate using Iterator (safe removal)
        Iterator<Integer> it = numbers.iterator();
        while (it.hasNext()) {
            int num = it.next();
            if (num < 30) {
                it.remove(); // Safe removal during iteration
            }
        }
        System.out.println("After removing numbers < 30: " + numbers);

        // Iterate using for-each
        System.out.print("Elements: ");
        for (int n : numbers) {
            System.out.print(n + " ");
        }
        System.out.println();

        // Find min and max
        System.out.println("Min: " + Collections.min(numbers));
        System.out.println("Max: " + Collections.max(numbers));
    }
}

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.stream.Collectors;

class Employee {
    String name;
    int age;
    double salary;

    Employee(String name, int age, double salary) {
        this.name = name;
        this.age = age;
        this.salary = salary;
    }

    @Override
    public String toString() {
        return name + "(age=" + age + ", salary=" + salary + ")";
    }
}

public class AdvancedArrayList {
    public static void main(String[] args) {
        List<Employee> employees = new ArrayList<>();
        employees.add(new Employee("Alice", 30, 75000));
        employees.add(new Employee("Bob", 25, 55000));
        employees.add(new Employee("Charlie", 35, 90000));
        employees.add(new Employee("Diana", 28, 68000));
        employees.add(new Employee("Eve", 32, 82000));

        // Sort by salary (ascending)
        employees.sort(Comparator.comparingDouble(e -> e.salary));
        System.out.println("Sorted by salary: " + employees);

        // Sort by age (descending)
        employees.sort(Comparator.comparingInt((Employee e) -> e.age).reversed());
        System.out.println("Sorted by age desc: " + employees);

        // Filter employees with salary > 70000 using Streams
        List<Employee> highEarners = employees.stream()
            .filter(e -> e.salary > 70000)
            .collect(Collectors.toList());
        System.out.println("High earners: " + highEarners);

        // Get names of employees under 30
        List<String> youngNames = employees.stream()
            .filter(e -> e.age < 30)
            .map(e -> e.name)
            .collect(Collectors.toList());
        System.out.println("Young employees: " + youngNames);

        // Calculate total salary
        double totalSalary = employees.stream()
            .mapToDouble(e -> e.salary)
            .sum();
        System.out.println("Total salary: " + totalSalary);

        // Average age
        double avgAge = employees.stream()
            .mapToInt(e -> e.age)
            .average()
            .orElse(0);
        System.out.println("Average age: " + avgAge);
    }
}

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

class CartItem {
    private String productName;
    private int quantity;
    private double pricePerUnit;

    public CartItem(String productName, int quantity, double pricePerUnit) {
        this.productName = productName;
        this.quantity = quantity;
        this.pricePerUnit = pricePerUnit;
    }

    public String getProductName() { return productName; }
    public int getQuantity() { return quantity; }
    public void setQuantity(int quantity) { this.quantity = quantity; }
    public double getPricePerUnit() { return pricePerUnit; }
    public double getTotalPrice() { return quantity * pricePerUnit; }

    @Override
    public String toString() {
        return String.format("%-15s x%d @ $%.2f = $%.2f",
            productName, quantity, pricePerUnit, getTotalPrice());
    }
}

class ShoppingCart {
    private List<CartItem> items = new ArrayList<>();

    public void addItem(String name, int qty, double price) {
        Optional<CartItem> existing = items.stream()
            .filter(i -> i.getProductName().equalsIgnoreCase(name))
            .findFirst();
        if (existing.isPresent()) {
            existing.get().setQuantity(existing.get().getQuantity() + qty);
            System.out.println("Updated quantity for: " + name);
        } else {
            items.add(new CartItem(name, qty, price));
            System.out.println("Added to cart: " + name);
        }
    }

    public void removeItem(String name) {
        boolean removed = items.removeIf(i -> i.getProductName().equalsIgnoreCase(name));
        System.out.println(removed ? "Removed: " + name : "Item not found: " + name);
    }

    public void displayCart() {
        System.out.println("\n=== Shopping Cart ===");
        if (items.isEmpty()) {
            System.out.println("Cart is empty.");
            return;
        }
        items.forEach(System.out::println);
        double total = items.stream().mapToDouble(CartItem::getTotalPrice).sum();
        System.out.printf("Total: $%.2f%n", total);
        System.out.println("Items in cart: " + items.size());
    }
}

public class ShoppingCartApp {
    public static void main(String[] args) {
        ShoppingCart cart = new ShoppingCart();
        cart.addItem("Laptop", 1, 999.99);
        cart.addItem("Mouse", 2, 29.99);
        cart.addItem("Keyboard", 1, 79.99);
        cart.addItem("Mouse", 1, 29.99); // Should update quantity
        cart.displayCart();
        cart.removeItem("Keyboard");
        cart.displayCart();
    }
}

