import java.util.*;

public class UniqueElements {
    public static List<Integer> findUnique(List<Integer> input) {
        Map<Integer, Integer> freq = new LinkedHashMap<>();
        for (int num : input) {
            freq.put(num, freq.getOrDefault(num, 0) + 1);
        }
        List<Integer> result = new ArrayList<>();
        for (Map.Entry<Integer, Integer> entry : freq.entrySet()) {
            if (entry.getValue() == 1) {
                result.add(entry.getKey());
            }
        }
        return result;
    }

    public static void main(String[] args) {
        List<Integer> input = new ArrayList<>(Arrays.asList(1, 2, 3, 2, 4, 3, 5, 1, 6));
        System.out.println("Unique elements: " + findUnique(input));
    }
}

import java.util.*;

class Student {
    String name;
    int score;
    Student(String name, int score) {
        this.name = name;
        this.score = score;
    }
}

public class TopStudents {
    public static List<String> getTop3(List<String> names, List<Integer> scores) {
        List<Student> students = new ArrayList<>();
        for (int i = 0; i < names.size(); i++) {
            students.add(new Student(names.get(i), scores.get(i)));
        }
        students.sort(Comparator.comparingInt((Student s) -> s.score)
            .reversed()
            .thenComparing(s -> s.name));
        List<String> result = new ArrayList<>();
        for (int i = 0; i < 3; i++) {
            result.add(students.get(i).name);
        }
        return result;
    }

    public static void main(String[] args) {
        List<String> names = Arrays.asList("Alice", "Bob", "Charlie", "Diana", "Eve");
        List<Integer> scores = Arrays.asList(85, 92, 78, 92, 88);
        System.out.println("Top 3: " + getTop3(names, scores));
    }
}
